namespace sv_2eb8e1efa7fc49c59062ae90de1e9549.Services;

public class WarehouseStateService
{
    private string _currentWarehouseId = "WH-1";

    public event Action? OnChange;

    public string CurrentWarehouseId
    {
        get => _currentWarehouseId;
        set
        {
            if (_currentWarehouseId == value)
                return;

            _currentWarehouseId = value;
            OnChange?.Invoke();
        }
    }

    public static IReadOnlyList<(string Id, string Name)> AvailableWarehouses { get; } =
    [
        ("WH-1", "Warehouse A — Downtown"),
        ("WH-2", "Warehouse B — Airport"),
        ("WH-3", "Warehouse C — Harbor"),
    ];
}

namespace sv_2eb8e1efa7fc49c59062ae90de1e9549.Services;

public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;
    private readonly Lock _lock = new();

    public int LatestLowStockCount { get; private set; }

    public event Func<Task>? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChanged;
    }

    /// <summary>Simulates a database query for low-stock items.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a component wants polling to be active.
    /// Polling runs as long as at least one subscriber exists.
    /// </summary>
    public void Subscribe()
    {
        lock (_lock)
        {
            _subscriberCount++;
            if (_subscriberCount == 1)
                StartPolling();
        }
    }

    /// <summary>
    /// Call when a component no longer needs polling.
    /// Polling stops when all subscribers have unsubscribed.
    /// </summary>
    public void Unsubscribe()
    {
        lock (_lock)
        {
            _subscriberCount = Math.Max(0, _subscriberCount - 1);
            if (_subscriberCount == 0)
                StopPolling();
        }
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire immediately on first subscribe, then every 10 s.
        await RefreshAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (_timer is null || !await _timer.WaitForNextTickAsync(ct))
                    break;

                await RefreshAsync();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task RefreshAsync()
    {
        LatestLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }

    private async void HandleWarehouseChanged()
    {
        // When the warehouse changes, refresh immediately so all
        // subscribers see the new warehouse's alert count.
        if (_subscriberCount > 0)
            await RefreshAsync();
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChanged;
        StopPolling();
    }
}

